To run the simple example query only, use the index definition in
the **Single Synonym Mapping** tab below. If you have an `M10` or
higher cluster and if you loaded both the example synonyms source
collections, you can run both the simple and advanced example queries
using the index definition that specifies multiple synonym mappings
in the **Multiple Synonym Mappings** tab below.

Single Synonym Mapping

Create a `create_index.go` file in your project directory,
and copy and paste the following code into the file.

The following index definition specifies:

- The [Language awareness](ref-language-analyzers)
  `lucene.english` as the default analyzer for both indexing
  and querying the `title` field.

- The name `transportSynonyms` as the name for this synonym
  mapping.

- The `transport_synonyms` collection as the source synonyms
  collection to look for synonyms for queries using
  `transportSynonyms` mapping. `transportSynonyms` can be
  used in text queries over any field indexed with the
  `lucene.english` analyzer (including the `title` field,
  in this example).

```go
package main

import (
	"context"
	"fmt"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}

	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()

	coll := client.Database("sample_mflix").Collection("movies")
	const indexName = "default"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the MongoDB Search index
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", false},
				{"fields", bson.D{
					{"title", bson.D{
						{"analyzer", "lucene.english"},
						{"type", "string"},
					}},
				}},
			}},
			{"synonyms", bson.A{
				bson.D{
					{"analyzer", "lucene.english"},
					{"name", "transportSynonyms"},
					{"source", bson.D{
						{"collection", "transport_synonyms"},
					}},
				},
			}},
		},
		Options: opts,
	}

	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}

	fmt.Println("New index name: " + searchIndexName)
}
```

Multiple Synonym Mappings

Create a `create_index_multiple.go` file in your project directory,
and copy and paste the following code into the file.

The following index definition specifies:

- The [Language awareness](ref-language-analyzers)
  `lucene.english` as the default analyzer for both indexing
  and querying the `title` field.

- Two synonym mappings: `transportSynonyms` and `attireSynonyms`.

- The `transport_synonyms` collection as the source for the
  `transportSynonyms` mapping.

- The `attire_synonyms` collection as the source for the
  `attireSynonyms` mapping.

```go
package main

import (
	"context"
	"fmt"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}

	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()

	coll := client.Database("sample_mflix").Collection("movies")
	const indexName = "default"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the MongoDB Search index
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", false},
				{"fields", bson.D{
					{"title", bson.D{
						{"analyzer", "lucene.english"},
						{"type", "string"},
					}},
				}},
			}},
			{"synonyms", bson.A{
				bson.D{
					{"analyzer", "lucene.english"},
					{"name", "transportSynonyms"},
					{"source", bson.D{
						{"collection", "transport_synonyms"},
					}},
				},
				bson.D{
					{"analyzer", "lucene.english"},
					{"name", "attireSynonyms"},
					{"source", bson.D{
						{"collection", "attire_synonyms"},
					}},
				},
			}},
		},
		Options: opts,
	}

	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}

	fmt.Println("New index name: " + searchIndexName)
}
```

Replace `<connection-string>` with the connection string for your
Atlas cluster or local Atlas deployment.

Atlas Cluster

Your connection string should use the following format:

```
mongodb+srv://<db_username>:<db_password>@<clusterName>.<hostname>.mongodb.net
```

To learn more, see [Driver](connect-via-driver).

Local or Self-Managed

Your connection string should use the
following format:

```
mongodb://localhost:<port-number>/?directConnection=true
```

To learn more, see [Connection Strings](manual/reference/connection-string).

